exercise.solutionCode:
public class Main {

    public static double computeAverage(int[] s) {
        int total = 0;
        for (int v : s) total += v;
        return (double) total / s.length;
    }

    public static String assignGrade(double avg) {
        if      (avg >= 90) return "A";
        else if (avg >= 75) return "B";
        else if (avg >= 60) return "C";
        else                return "F";
    }

    public static String getRemark(String grade) {
        switch (grade) {
            case "A": return "Excellent!";
            case "B": return "Well done!";
            case "C": return "Keep going!";
            default : return "Seek help.";
        }
    }

    public static void main(String[] args) {
        String[] names  = {"Rahul", "Priya", "Amit", "Sneha", "Vikram"};
        int[][]  scores = {
            {85, 72, 90}, {92, 88, 95}, {62, 55, 70},
            {78, 83, 91}, {45, 50, 48}
        };

        for (int i = 0; i < names.length; i++) {
            double avg    = computeAverage(scores[i]);
            String grade  = assignGrade(avg);
            String remark = getRemark(grade);
            System.out.println(names[i] + " " + grade + " " + remark);
        }
    }
}
